import { useState, useEffect } from 'react';
import Button from '../components/Button';

export default function TasksPage() {

  const domain = localStorage.getItem("selectedDomain") || "ai-and-ml";
  const timeline = localStorage.getItem("timeline") || "3 months";
  const totalDays = parseInt(timeline) * 30;

  const currentDay = parseInt(localStorage.getItem("currentDay") || "1");

  // ✅ SAME TOPIC MAP AS ROADMAP (IMPORTANT)
  const topicMap = {
    "ai-and-ml": [
      ["Python Basics → Datatypes (int, float, string)"],
      ["Variables & Input/Output"],
      ["Loops (for, while)", "Conditions (if, else)"],
      ["Functions (def, return)"],
      ["NumPy → Arrays, Indexing"],
      ["Pandas → DataFrames"],
      ["Visualization → Matplotlib"],
      ["Statistics → Mean, Median"],
      ["ML → Linear Regression"],
      ["Model Evaluation → Accuracy"],
      ["Deep Learning → Neural Networks"],
      ["Project → Build ML Model"]
    ],

    "web-development": [
      ["HTML → Tags, Structure"],
      ["CSS → Selectors, Box Model"],
      ["Flexbox, Grid"],
      ["JavaScript → Variables"],
      ["Functions, DOM"],
      ["ES6 → Arrow Functions"],
      ["React → Components"],
      ["Hooks (useState)"],
      ["API → Fetch"],
      ["Node.js → Express"],
      ["MongoDB → CRUD"],
      ["Project → Full Stack"]
    ]
  };

  const topics = topicMap[domain] || [["Learn basics"]];

  // ✅ FIXED: SAME LOGIC AS ROADMAP
  const getTasksForDay = () => {
    const index = (currentDay - 1) % topics.length; // 🔥 FIX
    const baseTasks = topics[index] || [];

    const carry = JSON.parse(localStorage.getItem("carryForward") || "[]");

    return [...new Set([...carry, ...baseTasks])]; // remove duplicates
  };

  const [tasks, setTasks] = useState([]);

  // ✅ Initialize tasks (sync with roadmap)
  useEffect(() => {
    const todayTasks = getTasksForDay().map((task, i) => ({
      id: i + 1,
      label: task,
      done: false
    }));
    setTasks(todayTasks);
  }, [currentDay]);

  const [newTaskLabel, setNewTaskLabel] = useState('');
  const [taskError, setTaskError] = useState('');

  const toggleTask = (id) => {
    setTasks(tasks.map((task) =>
      task.id === id ? { ...task, done: !task.done } : task
    ));
  };

  const handleAddTask = () => {
    if (!newTaskLabel.trim()) {
      setTaskError('Task label cannot be empty');
      return;
    }

    const newTask = {
      id: tasks.length + 1,
      label: newTaskLabel.trim(),
      done: false,
    };

    setTasks([...tasks, newTask]);
    setNewTaskLabel('');
    setTaskError('');
  };

  // ✅ SAVE PROGRESS (KEY LOGIC)
  const handleSaveProgress = () => {
    const remaining = tasks
      .filter(task => !task.done)
      .map(task => task.label);

    // store unfinished tasks
    localStorage.setItem("carryForward", JSON.stringify(remaining));

    // move to next day
    localStorage.setItem("currentDay", currentDay + 1);

    alert("Progress saved! Next day updated.");
    
  };

  return (
    <div className="space-y-8">
      <div className="rounded-[2rem] border border-slate-300 bg-gradient-to-br from-white to-blue-50 p-8 shadow-lg dark:border-slate-600 dark:from-slate-800 dark:to-slate-800">

        <h2 className="text-3xl font-semibold text-slate-900 dark:text-slate-50">
          Day {currentDay} Tasks
        </h2>

        <p className="mt-3 text-slate-600 dark:text-slate-300">
          Complete your tasks. Unfinished tasks will move to next day.
        </p>

        {/* Tasks */}
        <div className="mt-8 space-y-4">
          {tasks.map((task) => (
            <button
              key={task.id}
              type="button"
              onClick={() => toggleTask(task.id)}
              className={`flex w-full items-center justify-between rounded-3xl border px-5 py-4 text-left transition font-medium ${
                task.done
                  ? 'border-teal-300 bg-teal-100 text-teal-900 dark:bg-slate-700'
                  : 'border-slate-300 bg-white hover:border-teal-300 dark:bg-slate-800'
              }`}
            >
              <span>{task.label}</span>
              <span className="text-sm">{task.done ? '✓ Done' : 'Pending'}</span>
            </button>
          ))}
        </div>

        {/* Add Task */}
        <div className="mt-6 rounded-3xl border bg-slate-50 p-5 dark:bg-slate-900">
          <label className="block text-sm font-medium">New task</label>

          <div className="mt-3 flex gap-3">
            <input
              value={newTaskLabel}
              onChange={(e) => setNewTaskLabel(e.target.value)}
              placeholder="Add a new study task"
              className="flex-1 rounded-3xl border px-4 py-3"
            />
            <Button onClick={handleAddTask}>Add</Button>
          </div>

          {taskError && (
            <p className="mt-2 text-sm text-red-600">{taskError}</p>
          )}
        </div>

        {/* Save */}
        <div className="mt-6">
          <Button onClick={handleSaveProgress} className="w-full">
            Save Progress & Continue
          </Button>
        </div>

      </div>
    </div>
  );
}
